window.addEventListener('load', function() {
  var otherTab = window.open('https://example.com/other-tab');
  otherTab.postMessage('Hello, other tab!', '*');
});

// Tab 2
window.addEventListener('message', function(event) {
  if (event.origin === 'https://example.com') {
    console.log(event.data); // prints "Hello, other tab!"
  }
});
```
